DROP TABLE IF EXISTS `robot`;
CREATE TABLE `robot`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `robot_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '机器人编码（唯一标识）',
  `robot_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '机器人名称',
  `robot_type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '机器人类型（如测试机器人、thread）',
  `status` tinyint NOT NULL DEFAULT 0 COMMENT '状态：0-离线，1-在线，2-故障',
  `current_task_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '当前执行任务编码（空闲为NULL）',
  `last_heartbeat` datetime NULL DEFAULT NULL COMMENT '最后心跳时间（用于监控在线状态）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `description` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '描述',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_robot_code`(`robot_code` ASC) USING BTREE COMMENT '确保机器人编码唯一'
) ENGINE = InnoDB AUTO_INCREMENT = 8 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '机器人管理表' ROW_FORMAT = Dynamic;

