INSERT INTO `process_step` VALUES (7, 'TEST', 1, '数据采集测试', 'JAVA', '// 检查注入变量\nif (taskId == null) throw new RuntimeException(\"未注入 taskId\")\nif (enterpriseName == null) throw new RuntimeException(\"未注入 enterpriseName\")\n\n// 构建请求参数\ndef request = [:]\nrequest.taskId = taskId\nrequest.enterpriseName = enterpriseName\nrequest.appDate = \"2024-02-06\"\nrequest.baseUrl = \"http://study.zmyfrank.com:18010/spider/#\"\nrequest.headless = true\n\n// 执行采集\nimport com.rbac.core.domain.entity.RpaDataCollection\nimport com.rbac.core.spider.PlaywrightSpiderWebClient\nimport com.rbac.core.spider.CollectedPayload\n\n// 创建采集对象\nRpaDataCollection collection = new RpaDataCollection()\ncollection.setTaskId(taskId)\ncollection.setEnterpriseName(enterpriseName)\ncollection.setDataSource(\"spider_web\")\ncollection.setCollectionTime(java.time.LocalDateTime.now())\ncollection.setStatus(\"collected\")\ncollection.setDeleted(0)\n\ntry {\n    // 执行网页采集\n    PlaywrightSpiderWebClient client = new PlaywrightSpiderWebClient()\n    CollectedPayload payload = client.collect(request.baseUrl, request.headless, request.enterpriseName, request.appDate)\n    \n    // 设置采集结果\n    collection.setTaxNo(payload.getTaxNo())\n    collection.setRawData(objectMapper.writeValueAsString(payload))\n    \n    // 插入数据库\n    collectionMapper.insert(collection)\n    \n    // 确保返回正确的JSON格式\n    return \"{\\\"collectionId\\\": ${collection.id}}\"\n} catch (Exception e) {\n    collection.setStatus(\"failed\")\n    collection.setErrorMessage(e.getMessage().take(2000))\n    collection.setRawData(null)\n    collectionMapper.insert(collection)\n    throw e\n}', '2026-04-14 14:56:42', '2026-04-14 14:56:42', '数据采集测试');
INSERT INTO `process_step` VALUES (8, 'TEST', 2, '数据解析测试', 'JAVA', '// 检查注入变量\n// 尝试直接获取collectionId（因为它应该已经被注入到脚本环境中）\nif (collectionId == null) throw new RuntimeException(\"未找到collectionId\")\n\n// 执行解析\nimport com.rbac.core.domain.entity.RpaDataCollection\nimport com.rbac.core.domain.entity.RpaDataParsing\nimport com.rbac.core.spider.CollectedPayload\nimport com.rbac.common.utils.IndicatorDateUtil\n\n// 获取采集记录\nRpaDataCollection collection = collectionMapper.selectById(collectionId)\nif (collection == null) throw new RuntimeException(\"采集记录不存在: collectionId=\" + collectionId)\n\n// 创建解析对象\nRpaDataParsing parsing = new RpaDataParsing()\nparsing.setCollectionId(collection.getId())\nparsing.setTaskId(collection.getTaskId())\nparsing.setTaxNo(collection.getTaxNo())\nparsing.setEnterpriseName(collection.getEnterpriseName())\nparsing.setParsingTime(java.time.LocalDateTime.now())\nparsing.setStatus(\"parsed\")\nparsing.setDeleted(0)\n\ntry {\n    // 解析采集数据\n    CollectedPayload payload = objectMapper.readValue(collection.getRawData(), CollectedPayload.class)\n    def parsed = [:]\n    parsed.enterpriseName = payload.getEnterpriseName()\n    parsed.taxNo = payload.getTaxNo()\n    parsed.uscCode = payload.getUscCode()\n    parsed.appDate = payload.getAppDate()\n\n    def appDate = IndicatorDateUtil.parseAppDate(payload.getAppDate())\n    def invoices = []\n    for (row in payload.getInvoices()) {\n        def inv = [:]\n        inv.sign = row.getSign()\n        inv.state = row.getState()\n        inv.invoiceTime = row.getInvoiceTime()\n        inv.jshjText = row.getJshjText()\n\n        // 尝试解析，失败也保留原字段\n        if (IndicatorDateUtil.tryParseInvoiceTime(row.getInvoiceTime())) {\n            def invoiceTime = IndicatorDateUtil.parseInvoiceTime(row.getInvoiceTime())\n            inv.invoiceTimeParsed = invoiceTime.toString()\n            def diffMonths = (appDate.getYear() - invoiceTime.getYear()) * 12 + (appDate.getMonthValue() - invoiceTime.getMonthValue())\n            inv.monthDiffToAppDate = diffMonths\n        }\n        invoices.add(inv)\n    }\n    parsed.invoices = invoices\n    parsing.setParsedData(objectMapper.writeValueAsString(parsed))\n\n    // 插入数据库\n    parsingMapper.insert(parsing)\n    \n    // 更新采集状态\n    collection.setStatus(\"parsed\")\n    collectionMapper.updateById(collection)\n    \n    return \"{\\\"parsingId\\\": ${parsing.id}}\"\n} catch (Exception e) {\n    parsing.setStatus(\"failed\")\n    parsing.setErrorMessage(e.getMessage().take(2000))\n    parsingMapper.insert(parsing)\n    \n    // 更新采集状态\n    collection.setStatus(\"failed\")\n    collection.setErrorMessage(e.getMessage().take(2000))\n    collectionMapper.updateById(collection)\n    \n    throw e\n}', '2026-04-14 15:05:21', '2026-04-14 15:05:21', '数据解析测试');
INSERT INTO `process_step` VALUES (9, 'TEST', 3, '数据加工测试', 'JAVA', '// 检查注入变量\nif (parsingId == null) throw new RuntimeException(\"未注入 parsingId\")\n\n// 执行加工\nimport com.rbac.core.domain.entity.RpaDataParsing\nimport com.rbac.core.domain.mapper.RpaDataParsingMapper\nimport com.rbac.core.spider.service.InvoiceScaleIndicatorPipelineService\n\n// 获取解析记录\nRpaDataParsing parsing = parsingMapper.selectById(parsingId)\nif (parsing == null) throw new RuntimeException(\"解析记录不存在: parsingId=\" + parsingId)\n\n// 执行加工\nInvoiceScaleIndicatorPipelineService service = new InvoiceScaleIndicatorPipelineService(collectionMapper, parsingMapper, processingMapper, queryMapper, objectMapper)\ndef processing = service.processStep(parsing)\nreturn \"{\\\"processingId\\\": ${processing.id}}\"', '2026-04-14 15:05:46', '2026-04-14 15:05:46', '数据加工测试');
INSERT INTO `process_step` VALUES (10, 'TEST', 4, '数据完成测试', 'JAVA', '// 检查注入变量\nif (collectionId == null || parsingId == null || processingId == null) {\n    throw new RuntimeException(\"缺少必要的ID参数\")\n}\n\n// 执行完成\nimport com.rbac.core.domain.entity.RpaDataCollection\nimport com.rbac.core.domain.entity.RpaDataParsing\nimport com.rbac.core.domain.entity.RpaDataProcessing\nimport com.rbac.core.domain.mapper.RpaDataCollectionMapper\nimport com.rbac.core.domain.mapper.RpaDataParsingMapper\nimport com.rbac.core.domain.mapper.RpaDataProcessingMapper\nimport com.rbac.core.spider.service.InvoiceScaleIndicatorPipelineService\n\n// 获取各步骤记录\nRpaDataCollection collection = collectionMapper.selectById(collectionId)\nRpaDataParsing parsing = parsingMapper.selectById(parsingId)\nRpaDataProcessing processing = processingMapper.selectById(processingId)\n\nif (collection == null || parsing == null || processing == null) {\n    throw new RuntimeException(\"采集/解析/加工记录不存在\")\n}\n\n// 执行完成\nInvoiceScaleIndicatorPipelineService service = new InvoiceScaleIndicatorPipelineService(collectionMapper, parsingMapper, processingMapper, queryMapper, objectMapper)\ndef query = service.completeStep(collection, parsing, processing)\nreturn \"{\\\"queryId\\\": ${query.id}}\"', '2026-04-14 15:06:07', '2026-04-14 15:06:07', '数据完成测试');
INSERT INTO `process_step` VALUES (11, 'TEST2', 1, '数据采集测试', 'JAVA', '// 检查注入变量\nif (taskId == null) throw new RuntimeException(\"未注入 taskId\")\nif (enterpriseName == null) throw new RuntimeException(\"未注入 enterpriseName\")\n\n// 构建请求参数\ndef request = [:]\nrequest.taskId = taskId\nrequest.enterpriseName = enterpriseName\nrequest.appDate = \"2024-02-06\"\nrequest.baseUrl = \"http://study.zmyfrank.com:18010/spider/#\"\nrequest.headless = true\n\n// 执行采集\nimport com.rbac.core.domain.entity.RpaDataCollection\nimport com.rbac.core.spider.PlaywrightSpiderWebClient\nimport com.rbac.core.spider.CollectedPayload\n\n// 创建采集对象\nRpaDataCollection collection = new RpaDataCollection()\ncollection.setTaskId(taskId)\ncollection.setEnterpriseName(enterpriseName)\ncollection.setDataSource(\"spider_web\")\ncollection.setCollectionTime(java.time.LocalDateTime.now())\ncollection.setStatus(\"collected\")\ncollection.setDeleted(0)\n\ntry {\n    // 执行网页采集\n    PlaywrightSpiderWebClient client = new PlaywrightSpiderWebClient()\n    CollectedPayload payload = client.collect(request.baseUrl, request.headless, request.enterpriseName, request.appDate)\n    \n    // 设置采集结果\n    collection.setTaxNo(payload.getTaxNo())\n    collection.setRawData(objectMapper.writeValueAsString(payload))\n    \n    // 插入数据库\n    collectionMapper.insert(collection)\n    \n    // 确保返回正确的JSON格式\n    return \"{\\\"collectionId\\\": ${collection.id}}\"\n} catch (Exception e) {\n    collection.setStatus(\"failed\")\n    collection.setErrorMessage(e.getMessage().take(2000))\n    collection.setRawData(null)\n    collectionMapper.insert(collection)\n    throw e\n}', '2026-04-15 09:22:56', '2026-04-15 09:48:29', '数据采集测试');
INSERT INTO `process_step` VALUES (12, 'TEST2', 2, '测试代码发生错误的流程2', 'JAVA', '// 检查注入变量\n// 尝试直接获取collectionId（因为它应该已经被注入到脚本环境中）\nif (collectionId == null) throw new (\"未找到collectionId\")\n\n// 执行解析\nimport com.rbac.core.domain.entity.RpaDataCollection\nimport com.rbac.core.domain.entity.RpaDataParsing\nimport com.rbac.core.spider.CollectedPayload\nimport com.rbac.common.utils.IndicatorDateUtil\n\n// 获取采集记录\nRpaDataCollection collection = collectionMapper.selectById(collectionId)\nif (collection == null) throw new RuntimeException(\"采集记录不存在: collectionId=\" + collectionId)\n\n// 创建解析对象\nRpaDataParsing parsing = new RpaDataParsing()\nparsing.setCollectionId(collection.getId())\nparsing.setTaskId(collection.getTaskId())\nparsing.setTaxNo(collection.getTaxNo())\nparsing.setEnterpriseName(collection.getEnterpriseName())\nparsing.setParsingTime(java.time.LocalDateTime.now())\nparsing.setStatus(\"parsed\")\nparsing.setDeleted(0)\n\ntry {\n    // 解析采集数据\n    CollectedPayload payload = objectMapper.readValue(collection.getRawData(), CollectedPayload.class)\n    def parsed = [:]\n    parsed.enterpriseName = payload.getEnterpriseName()\n    parsed.taxNo = payload.getTaxNo()\n    parsed.uscCode = payload.getUscCode()\n    parsed.appDate = payload.getAppDate()\n\n    def appDate = IndicatorDateUtil.parseAppDate(payload.getAppDate())\n    def invoices = []\n    for (row in payload.getInvoices()) {\n        def inv = [:]\n        inv.sign = row.getSign()\n        inv.state = row.getState()\n        inv.invoiceTime = row.getInvoiceTime()\n        inv.jshjText = row.getJshjText()\n\n        // 尝试解析，失败也保留原字段\n        if (IndicatorDateUtil.tryParseInvoiceTime(row.getInvoiceTime())) {\n            def invoiceTime = IndicatorDateUtil.parseInvoiceTime(row.getInvoiceTime())\n            inv.invoiceTimeParsed = invoiceTime.toString()\n            def diffMonths = (appDate.getYear() - invoiceTime.getYear()) * 12 + (appDate.getMonthValue() - invoiceTime.getMonthValue())\n            inv.monthDiffToAppDate = diffMonths\n        }\n        invoices.add(inv)\n    }\n    parsed.invoices = invoices\n    parsing.setParsedData(objectMapper.writeValueAsString(parsed))\n\n    // 插入数据库\n    parsingMapper.insert(parsing)\n    \n    // 更新采集状态\n    collection.setStatus(\"parsed\")\n    collectionMapper.updateById(collection)\n    \n    return \"{\\\"parsingId\\\": ${parsing.id}}\"\n} catch (Exception e) {\n    parsing.setStatus(\"failed\")\n    parsing.setErrorMessage(e.getMessage().take(2000))\n    parsingMapper.insert(parsing)\n    \n    // 更新采集状态\n    collection.setStatus(\"failed\")\n    collection.setErrorMessage(e.getMessage().take(2000))\n    collectionMapper.updateById(collection)\n    \n    throw e\n}', '2026-04-15 09:49:31', '2026-04-15 09:49:31', '测试代码发生错误的流程');
